from dataclasses import dataclass
from datetime import datetime
from typing import List, Dict, Any

@dataclass
class User:
    id: int
    name: str
    signup_ts: datetime
    is_active: bool

def _to_int(v: Any) -> int:
    if isinstance(v, int):
        return v
    return int(v)

def _parse_ts(ts: Any) -> datetime:
    if isinstance(ts, datetime):
        return ts
    return datetime.fromisoformat(ts)

def _to_bool(v: Any) -> bool:
    if isinstance(v, bool):
        return v
    if isinstance(v, str):
        return v.strip().lower() in {"true", "1", "yes", "y"}
    return bool(v)


def normalize_users(users: List[Dict[str, Any]]) -> List[User]:
    out: List[User] = []
    bad: List[int] = []
    for i, rec in enumerate(users):
        try:
            u = User(
                id=_to_int(rec.get("id")),
                name=rec.get("name", ""),
                signup_ts=_parse_ts(rec.get("signup_ts")),
                is_active=_to_bool(rec.get("is_active", False)),
            )
            out.append(u)
        except Exception:
            bad.append(i)
    if bad:
        raise ValueError(f"Invalid records at indices: {bad}")
    return out
```

