from datetime import datetime

def stream_group_actions_by_user(file_path, batch_size=1000):
    allowed = {'login', 'click', 'purchase'}
    batch = {}
    bad = 0
    with open(file_path, newline='') as f:
        reader = csv.reader(f)
        for i, row in enumerate(reader, 1):
            if len(row) != 4:
                bad += 1
                continue
            ts, user, action, value = row
