                bad += 1
                continue
            rec = {'timestamp': ts_dt.isoformat(), 'action': action, 'value': value_f}
            batch.setdefault(user, []).append(rec)
            if i % batch_size == 0:
                yield {u: list(recs) for u, recs in batch.items()}
                batch.clear()
    if batch:
        yield {u: list(recs) for u, recs in batch.items()}
