from __future__ import annotations
import json
from dataclasses import dataclass
from typing import Iterator, TextIO

@dataclass
class Event:
    id: str
    action: str
    ts: int

VALID_ACTIONS = {"click", "view", "purchase"}

def validate(line: str) -> Event:
    obj = json.loads(line)
    if not isinstance(obj.get("id"), str):
        raise ValueError("invalid id")
    if obj.get("action") not in VALID_ACTIONS:
        raise ValueError("invalid action")
    if not isinstance(obj.get("ts"), int):
        raise ValueError("invalid ts")
    return Event(id=obj["id"], action=obj["action"], ts=obj["ts"])

def stream_ndjson(src: TextIO) -> Iterator[Event]:
    invalid = 0
    for line in src:
        line = line.strip()
        if not line:
            continue
        try:
            yield validate(line)
        except Exception:
            invalid += 1
    print(f"Invalid lines: {invalid}")
```

