def sanitize_events(stream):
    import json
    for line in stream:
        try:
            obj = json.loads(line)
        except Exception:
            continue
        if not isinstance(obj, dict):
            continue
        if not all(k in obj for k in ("user_id","email","action","ts")):
            continue
        if not isinstance(obj["user_id"], str):
            continue
        if not isinstance(obj["email"], str):
            continue
        if not isinstance(obj["action"], str):
            continue
        if not isinstance(obj["ts"], int):
            continue
        email = obj["email"]
        local, _, domain = email.partition("@")
        if len(local) <= 2:
            masked_local = "*" * len(local)
        else:
            masked_local = local[0] + "*" * (len(local) - 2) + local[-1]
        masked_email = masked_local + "@" + domain
        out = {"user_id": obj["user_id"], "email": masked_email, "action": obj["action"], "ts": obj["ts"]}
        if "phone" in obj:
            out["phone"] = "REDACTED"
        yield out
```

