from typing import TypedDict, Iterator, Dict
import json

class LogLine(TypedDict):
    level: str
    ts: int
    msg: str

def process_logs(stream: Iterator[str], batch_size: int = 50):
    counts: Dict[str, int] = {}
    total = 0
    errors = 0
    for line in stream:
        total += 1
        try:
            data = json.loads(line)
            if not isinstance(data, dict) or not all(k in data for k in ("level", "ts", "msg")):
                raise ValueError("Invalid keys")
            log: LogLine = {"level": str(data["level"]), "ts": int(data["ts"]), "msg": str(data["msg"])}
            counts[log["level"]] = counts.get(log["level"], 0) + 1
        except Exception:
            errors += 1
        if total % batch_size == 0:
            yield {"counts": counts.copy(), "total": total, "errors": errors}
    if total % batch_size != 0:
        yield {"counts": counts, "total": total, "errors": errors}
```

## Follow-up Questions
- How would you extend this to handle out-of-order lines with timestamps? 
- How would you benchmark latency between input and snapshots?

## Why This Is Asked

Resilience in API calls is critical in fintech integrations; this tests practical handling of transient failures without blocking throttling.

## Key Concepts

- Exponential backoff with jitter
- Distinguishing async vs sync paths
- Exception filtering and retries
- Preserving function metadata with functools.wraps

## Code Example

```python
import asyncio
import functools
import random
import inspect
import time


def retry(max_retries=3, base_delay=0.1, jitter=0.05, retry_exceptions=(TimeoutError, ConnectionError)):
    def decorator(fn):
        @functools.wraps(fn)
        async def async_wrapper(*args, **kwargs):
            last_exc = None
            for i in range(max_retries + 1):
                try:
                    return await fn(*args, **kwargs)
                except retry_exceptions as e:
                    last_exc = e
                    if i == max_retries:
                        raise
                    delay = base_delay * (2 ** i) * (1 + random.uniform(-jitter, jitter))
                    await asyncio.sleep(delay)
        @functools.wraps(fn)
        def sync_wrapper(*args, **kwargs):
            last_exc = None
            for i in range(max_retries + 1):
                try:
                    return fn(*args, **kwargs)
                except retry_exceptions as e:
                    last_exc = e
                    if i == max_retries:
                        raise
                    delay = base_delay * (2 ** i) * (1 + random.uniform(-jitter, jitter))
                    time.sleep(delay)
        if inspect.iscoroutinefunction(fn):
            return async_wrapper
        else:
            return sync_wrapper
    return decorator
```

## Follow-up Questions

- How would you extend this for per-domain rate limiting in a multi-tenant fintech client?
- How would you test both sync and async paths for failure, success, and maximum backoffs?

